import{_ as a,o as b,c as t,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.8.侦测与反侦测","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/3.战斗规则/3.8.侦测与反侦测.md","filePath":"1.基础规则/3.战斗规则/3.8.侦测与反侦测.md"}'),n={name:"1.基础规则/3.战斗规则/3.8.侦测与反侦测.md"};function _(o,e,d,l,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"_3-8-侦测与反侦测",tabindex:"-1"},[p("3.8.侦测与反侦测 "),r("a",{class:"header-anchor",href:"#_3-8-侦测与反侦测","aria-label":'Permalink to "3.8.侦测与反侦测"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),s('<h1 id="侦测、定位与效果线" tabindex="-1">侦测、定位与效果线 <a class="header-anchor" href="#侦测、定位与效果线" aria-label="Permalink to &quot;侦测、定位与效果线&quot;">​</a></h1><p>侦测、定位与效果线</p><p>侦测与反侦测都会具有一个初始支线等级，对应它为某个等级的侦测/反侦测方式。侦测与反侦测都会具有其基础本质，分为四种：自然、科技，魔幻，特异，当双方的本质不同时，进行侦测的一方视为支线提升了一个级别。</p><p>侦测与反侦测对抗：根据使用者不同，这一对抗也可以被称为侦测对抗、反侦测对抗等。<br> 1、侦测等级对抗<br> 当一种侦测方式意图探测一种反侦测方式时，首先需要比对双方的支线等级，较高的一方获胜，若平级则按反侦测获胜处理，这是支线等级对抗。<br> 2、侦测检定对抗：<br> 若反侦测方在等级对抗中胜出，则无法直接被侦测手段定位，侦测方进行一次侦察检定以对抗对方的潜藏检定，反侦测方在这次检定中获得反侦测能力（D1C2B3A4S5，只计算基础等级）等级+2的附加成功，此时侦测方胜出可以获得反侦测方的模糊定位；<br> 若侦测方胜出，可无需判定，直接进行模糊定位并进行一次侦察检定以对抗对方的潜藏检定，侦测方在这次检定中获得侦测能力（D1C2B3A4S5，只计算基础等级）等级+2的附加成功，此时侦测方胜出可以获得反侦测方的精确定位；在支线等级对抗后的检定对抗为专业对抗。<br> 上述侦测方在等级对抗和检定对抗都失败，则无法对试图对反侦测方进行定位。<br> 对抗结束后，根据侦测方与反侦测方使用的能力实际可定位等级决定定位等级。<br> 当反侦测方进入侦测方敏感范围时，侦测方需以被动形式对反侦测方进行等级对抗和检定对抗。若对抗结果为模糊定位，侦测方可以主动进行侦测检定对抗以进一步侦测被侦测方的位置，将模糊定位升级为精确定位，这在战斗中为一个移动动作。</p><p>战斗中使用多种侦测方式、反侦测方式：<br> 反侦测能力或者侦测能力若没有特别声明，均可以自由动作启用或者关闭。<br> 当一个单位在战斗中使用了新的侦测方式（即战斗中首次使用），则他会获得一次对该侦测方式基于的感知范围内的单位进行侦测对抗的机会。<br> 当一个单位在战斗中使用了新的反侦测方式时，他也会获得一次以新的反侦测方式同侦测方进行新一轮侦测对抗的机会。<br> 当一个单位同时使用了多种侦测/反侦测能力，则其侦测/反侦测能力的本质以不同侦测/反侦测能力合并计算，侦测/反侦测能力的等级则取低计算。</p><p>若一个单位在无法定位的情况下进行社交行为，后续可能会发生的情况由st裁定</p><p>-对于敏感范围以外进行侦查时：<br> -每增加20米，侦查成功数-1。得到1成功数即可模糊定位，无法精确定位（仅对于没有任何特殊能力的单位而言；如果对方具有特殊能力，仍需要进行侦测对抗）<br> -侦查敏感范围以外的距离时，至少需要1轮/12秒时间；侦查的范围每增加敏感范围的一半，总的侦查时间就会增加一倍<br> -或者你也可以声明一定距离外等同你敏感范围大小的一块区域，你对这片区域的侦查只需要1轮时间，无论距离多远（但仍需承受侦查成功数的减值）。</p><p>定位等级：<br> 精确定位：精确定位指确切知道目标的位置。一般来说，对人类而言，如果能清楚明确且真实地看清目标，则可以定位它。人物可以无碍地攻击被定位的目标，或者对其使用那些“指定X个目标/指定范围内X个目标”的法术或能力。人物总可以精确定位一个位置（比如“我面前五米、高三米的地方”）<br> 模糊定位：大概知道目标的位置称为模糊定位。这意味着人物知道目标的大概方位，但不清楚具体位置。对人类来说，看不到人但能近距离听到持续的说话和嘈杂声，就有可能模糊定位。人物可以攻击被模糊定位的目标，但造成的伤害值和产生的效果点数都只计算一半，向下取整。人物也可以选择模糊定位的目标作为指定目标的技能或能力的目标，但技能只有一半概率成功（然而，如果法术或能力范围描述为“范围”或“范围内每个目标”，则照常生效）。<br> 无法定位：人物完全无法知道目标的位置。就人类而言，这意味着他看不到、听不到敌人，并且没有任何可供分析的数据。人物可以假定目标在某位置并进行攻击，若目标恰好在那个位置，则视为模糊定位。但人物不可能将他指定为技能或能力的目标（然而，如果技能或能力范围描述为“范围”或“范围内每个目标”，则照常生效）。<br> 如无特别说明，对于未进行躲藏、没有反侦测能力的目标，没有相关能力的普通人只能使用视觉来进行精确定位，或者以听觉进行敏感范围内的模糊定位。</p><p>在战斗中，若意图攻击一个已经暴露其模糊定位的目标，且攻击手段不为能整个将该攻击地区笼罩的攻击方式时，造成的对模糊定位一方的伤害检定出目、附加成功和产生的特殊效果都只生效一半，向较少的一方取整；若意图攻击一个不知是否存在的假想敌，则仅可以以范围攻击的形式对那个范围进行打击，不能指定那个范围使用具体到单位的单体能力和攻击；若已精确定位，则可以正常攻击</p><p>感知方式：<br> 线型感知方式：可在无影响感知的情况下进行精确定位和模糊定位，墙体、浓烟、污水等情况均可影响线型感知方式，相应的镜子等具有反射相关功能的情况可使线型感知方式延伸，若无特殊情况，视觉属于线型感知方式。<br> 非线型感知方式：可在特定情况发生时进行模糊定位，只有能影响特定情况被感知的因素才能影响线型感知方式，若无特殊情况，听觉属于非线型感知方式。<br> 强感知方式：通常是由某种能力带来的额外感知方式，或者由线型/非线型升级而来的感知方式，能够一定程度无视影响感知的情况，或者能够非线型精确定位特定情况。<br> 无/弱感知方式：只有在某些特定情况下才能进行模糊定位。<br> 人物初始具有视觉（线型）、听觉（非线型）、嗅觉（无）和触觉（无）这四种感知方式，<br> 处于目盲状态的人物无法以视觉定位目标。处于耳聋状态的人物无法以听觉定位目标。</p><p>感知范围、敏感范围：<br> 敏感范围是人物综合性的感知范围，若无特殊说明，大部分的感知方式都基于敏感范围生效。<br> 感知范围是仅限于指定感知方式的感知范围，通常而言它与敏感范围并无差别，但在部分资源的影响下，感知范围可能相较于敏感范围更大或者更小。</p><p>伪装【无支线】【有等级的伪装根据其具体的注明为准】<br> 伪装是一种弱反侦测，不具有本质，它不同于一般的反侦测手段。<br> 伪装不会影响通常意义上的定位对抗。<br> 具有某等级侦测方式的单位在对一个单位进行识破伪装为目标的调查检定时，会自动识破同等级及以下的伪装效果。</p><p>潜行<br> 潜行是一种特殊的行进方式，当你与敌方敏感范围进行侦测定位对抗后，若处于无法定位状态，则可选择进入潜行行走状态。潜行状态会导致以此法行走者移动速度减半，潜行者可以随时取消潜行行走状态，若如此做，则敏感范围内包含潜行者、具有相应感知方式的单位会获得潜行者的模糊定位。<br> 每轮开始时潜行者都需要与敏感范围内包含潜行者、具有相应感知方式的单位进行侦测定位对抗，若失败则会退出潜行状态，并承受定位对抗失败的后果。<br> 人物如果对其他单位处于可定位状态（模糊定位、精确定位），可花费一个移动动作进行一次半速移动以试图进入潜行状态，此时潜行者需要再度与敏感范围内包含潜行者的单位进行侦测定位对抗，若对抗成功则享受定位对抗成功的好处并进入潜行状态。<br> 在潜行行走的状态下，潜行者获得3点防御上的遮蔽加值，对无法定位潜行者的目标进行的攻击具有等于反侦测等级的措手不及。当潜行者进行攻击后，会脱离潜行状态。脱离潜行状态后，敏感范围内包含潜行者、具有相应感知方式的单位会获得潜行者的模糊定位。<br> 不能在保持伏地状态时进行潜行状态。<br> 如果一个单位具有潜行者的精确定位，则潜行者对于这一单位不处于潜行状态。<br> 注：潜行状态是潜行者对多个目标同时生效的状态，可能潜行者对于无法定位他的敌人A是潜行状态，对于可以精确定位他的敌人B是非潜行状态。但无论如何，潜行者脱离潜行状态一定是对所有敏感范围内包含潜行者的、具有相应感知方式的目标同时脱离潜行状态。</p><p>感知线与效果线：<br> 感知线：感知线是指通过感知形式收取信息的不存在连线，只要能精确定位或模糊定位就视为建立了感知线。<br> 效果线：效果线是指一种效果在生效时的方式，例如直线、球形等，判定一条效果线能否成功击中指定目标时，判定方式为两点沿途路径上没有阻碍物或可以成功击穿沿途所有阻碍物。</p><p>效果线的类型：<br> 直线型效果线：这部分效果线是最为多见的效果线，类似子弹射击、魔法射线、刀劈剑砍等行为都是此类效果线。基于直线型效果线的能力需要使用者与目标之间没有障碍物或者可以穿透沿途障碍物才可生效。<br> 曲线型效果线：这部分效果线相对少见，类似拐弯子弹、折射射线等。基于曲线型效果线的能力可以让使用者绕过大部分非全遮蔽的障碍物对目标生效。<br> 垂直型效果线：这部分效果线同样较为少见，例如卫星射线、召唤地刺等。基于垂直型效果线的能力需要目标的上方/下方没有障碍物遮挡才能生效。<br> 抛物线效果线：该效果线与直线型效果线类似，但是让能力可以一定程度的绕过障碍物对目标生效。抛物线形式的效果线生效会令目标获得一定程度的掩蔽加值，具体由St进行裁定。</p><p>通常而言，能力的默认效果线类型均为直线型效果线，具有特殊效果线的能力会在资源中提及。ST可根据一个资源的画风、具体情况判断一个能力的效果线类型。</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const m=a(n,[["render",_]]);export{f as __pageData,m as default};
